import React, { useRef, useEffect } from "react";
import { Chart, ArcElement, DoughnutController, Tooltip, Legend, BarElement, BarController, CategoryScale, LinearScale } from "chart.js";
import MetricCard from "../components/MetricCard";
import { StatusBadge, UrgencyBadge, CategoryBadge } from "../components/Badges";
import { useAnalytics } from "../hooks/useAnalytics";
import LoadingSpinner from "../components/LoadingSpinner";
import { formatDate, getInitials, getAvatarStyle, URGENCY_COLORS } from "../utils/helpers";
import { useNavigate } from "react-router-dom";

Chart.register(ArcElement, DoughnutController, Tooltip, Legend, BarElement, BarController, CategoryScale, LinearScale);

export default function AdminDashboard({ needs, volunteers, assignments }) {
  const navigate = useNavigate();
  const { analytics, loading } = useAnalytics();
  const doughnutRef = useRef(null);
  const barRef = useRef(null);
  const doughnutInst = useRef(null);
  const barInst = useRef(null);

  useEffect(() => {
    if (!doughnutRef.current || !analytics) return;
    if (doughnutInst.current) doughnutInst.current.destroy();
    doughnutInst.current = new Chart(doughnutRef.current, {
      type: "doughnut",
      data: {
        labels: ["Food", "Health", "Education", "Disaster"],
        datasets: [{
          data: [
            analytics.byCategory?.food || 0,
            analytics.byCategory?.health || 0,
            analytics.byCategory?.education || 0,
            analytics.byCategory?.disaster || 0,
          ],
          backgroundColor: ["#16a34a", "#dc2626", "#2563eb", "#d97706"],
          borderWidth: 0,
        }],
      },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } } },
    });
    return () => { if (doughnutInst.current) doughnutInst.current.destroy(); };
  }, [analytics]);

  useEffect(() => {
    if (!barRef.current || !analytics) return;
    if (barInst.current) barInst.current.destroy();
    barInst.current = new Chart(barRef.current, {
      type: "bar",
      data: {
        labels: ["Pending", "In Progress", "Completed"],
        datasets: [{
          data: [analytics.pendingNeeds, analytics.inProgressNeeds, analytics.completedNeeds],
          backgroundColor: ["#f1f5f9", "#fef9c3", "#dcfce7"],
          borderColor: ["#cbd5e1", "#fde047", "#86efac"],
          borderWidth: 1,
        }],
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: { legend: { display: false } },
        scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } } },
      },
    });
    return () => { if (barInst.current) barInst.current.destroy(); };
  }, [analytics]);

  if (loading) return <LoadingSpinner message="Loading admin dashboard..." />;

  const topNeeds = [...needs].filter((n) => n.status !== "completed").slice(0, 5);
  const recentAssignments = assignments.slice(-4).reverse();

  return (
    <div>
      <div style={{ marginBottom: 24 }}>
        <h2 style={{ fontSize: 24, fontWeight: 700, color: "#1e293b" }}>Admin Overview</h2>
        <p style={{ color: "#64748b" }}>Real-time triage and resource analytics</p>
      </div>

      {analytics?.urgentNeeds > 0 && (
        <div className="alert-bar" style={{ marginBottom: "1.5rem" }}>
          <span style={{ fontSize: 18 }}>⚡</span>
          <span>
            <strong>{analytics.urgentNeeds} critical needs</strong> require immediate volunteer assignment
          </span>
          <button className="btn btn-sm" onClick={() => navigate("/matching")} style={{ marginLeft: "auto", background: "rgba(74,222,128,0.15)", color: "#4ade80", borderColor: "#166534" }}>
            Match now →
          </button>
        </div>
      )}

      <div className="grid-4" style={{ marginBottom: "1.5rem" }}>
        <MetricCard label="Total Needs" value={analytics?.totalNeeds || 0} sub={`${analytics?.pendingNeeds || 0} pending`} />
        <MetricCard label="Critical Needs" value={analytics?.urgentNeeds || 0} sub="require action" color="#dc2626" />
        <MetricCard label="Active Volunteers" value={analytics?.availableVolunteers || 0} sub={`of ${analytics?.totalVolunteers || 0} total`} color="#16a34a" />
        <MetricCard label="People Helped" value={analytics?.totalPeopleHelped || 0} sub={`${analytics?.completedNeeds || 0} tasks done`} color="#2563eb" />
      </div>

      <div className="grid-2" style={{ marginBottom: "1.5rem" }}>
        <div className="card">
          <div className="section-title">Priority Queue</div>
          {topNeeds.length === 0 && <p style={{ color: "#94a3b8", fontSize: 13 }}>No active needs.</p>}
          {topNeeds.map((n) => (
            <div key={n.id} className="need-row">
              <div style={{ minWidth: 40 }}>
                <div style={{ fontSize: 16, fontWeight: 700, color: URGENCY_COLORS[n.urgency], fontFamily: "monospace" }}>{n.priorityScore}</div>
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 500, fontSize: 13 }}>{n.title}</div>
                <div style={{ display: "flex", gap: 4, marginTop: 3, flexWrap: "wrap" }}>
                  <UrgencyBadge urgency={n.urgency} />
                  <CategoryBadge category={n.category} />
                </div>
              </div>
              <div style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace" }}>{n.peopleAffected} ppl</div>
            </div>
          ))}
        </div>

        <div className="card">
          <div className="section-title">Needs by Category</div>
          <div style={{ position: "relative", height: 160, marginBottom: 12 }}>
            <canvas ref={doughnutRef} />
          </div>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 16 }}>
            {[["food", "#16a34a"], ["health", "#dc2626"], ["education", "#2563eb"], ["disaster", "#d97706"]].map(([c, col]) => (
              <div key={c} style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 12, color: "#64748b" }}>
                <span style={{ width: 10, height: 10, borderRadius: 2, background: col, flexShrink: 0 }} />
                {c.charAt(0).toUpperCase() + c.slice(1)}: {analytics?.byCategory?.[c] || 0}
              </div>
            ))}
          </div>
          <div className="section-title">Status Breakdown</div>
          <div style={{ position: "relative", height: 100 }}>
            <canvas ref={barRef} />
          </div>
        </div>
      </div>

      <div className="card">
        <div className="section-title">Recent Assignments</div>
        {recentAssignments.length === 0 && <p style={{ color: "#94a3b8", fontSize: 13 }}>No assignments yet.</p>}
        {recentAssignments.map((a, i) => {
          const vol = volunteers.find((v) => v.id === a.volunteerId);
          const need = needs.find((n) => n.id === a.needId);
          if (!vol || !need) return null;
          const style = getAvatarStyle(i);
          return (
            <div key={a.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 0", borderBottom: "1px solid #f8fafc" }}>
              <div className="vol-avatar" style={{ width: 28, height: 28, fontSize: 10, background: style.bg, color: style.color }}>
                {getInitials(vol.name)}
              </div>
              <span style={{ flex: 1, fontSize: 13, color: "#475569" }}>
                <strong>{vol.name}</strong> → {need.title}
              </span>
              <StatusBadge status={a.status} />
              <span style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace" }}>{formatDate(a.createdAt)}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
